// In the feature service
getEvidenceTypeOptions(): Promise<EnumDTO[]> {
  return firstValueFrom(
    this.http.get<EnumDTO[]>(`${environment.apiBaseUrl}/api/v1/lookups/evidence-types`),
  );
}

// In the component
readonly evidenceTypeOptions = signal<EnumDTO[]>([]);

async ngOnInit() {
  this.evidenceTypeOptions.set(await this.service.getEvidenceTypeOptions());
}

// action.enums.ts

export const ActionStatus = {
  Active: 'Active',
  Inactive: 'Inactive',
} as const;
export type ActionStatus = (typeof ActionStatus)[keyof typeof ActionStatus];
// yields: 'Active' | 'Inactive'

export const EvidenceType = {
  Public: 'Public',
  Confidential: 'Confidential',
} as const;
export type EvidenceType = (typeof EvidenceType)[keyof typeof EvidenceType];

import { ActionStatus, EvidenceType } from './action.enums';

// Conditional rendering
readonly isActive = computed(() =>
  this.dto()?.status.name === ActionStatus.Active
);

// Conditional styling
statusBadgeClass(status: EnumDTO): string {
  switch (status.name) {
    case ActionStatus.Active:
      return 'badge bg-success';
    case ActionStatus.Inactive:
      return 'badge bg-secondary';
    default:
      return '';
  }
}

// Guard logic
readonly canDelete = computed(() => {
  const action = this.dto();
  return app != null && !app.isCore && !app.isFirstParty;
});

readonly showSecretColumn = computed(() =>
  this.dto()?.evidence.some(c => c.evidenceType.name === EvidenceType.Confidential) ?? false
);

